import React from 'react';
import { useCurrentFrame, useVideoConfig } from 'remotion';
import { z } from 'zod';
import { DURATION } from '../../../lib/motion';
import { entryScale } from '../../../lib/choreography';

/** Zod schema for {@link IconPop} props. */
export const iconPopSchema = z.object({
  /** Which icon to render. */
  icon: z.enum(['check', 'cross', 'dot', 'star']).default('check'),
  /** Frames before the animation starts. */
  delay: z.number().int().min(0).default(0),
  /** Frames to settle. */
  duration: z.number().int().min(1).default(DURATION.base),
  /** Icon size in pixels (square). */
  size: z.number().default(96),
  /** Icon color. Defaults to `--onda-accent` (`#D96B82`) â€” accent earned. */
  color: z.string().default('#D96B82'),
  /** Stroke width for outline icons (check, cross). Ignored by filled icons. */
  strokeWidth: z.number().default(3),
});

/** Inferred props for {@link IconPop}. */
export type IconPopProps = z.infer<typeof iconPopSchema>;

/**
 * Path data for each icon variant, expressed inside the 0â€“24 viewBox.
 * Outline icons (`check`, `cross`) are stroked; filled icons (`dot`, `star`)
 * are filled. Kept inline so the component stays self-contained.
 */
const ICONS: Record<
  IconPopProps['icon'],
  { d: string; filled: boolean }
> = {
  check: { d: 'M5 13l4 4L19 7', filled: false },
  cross: { d: 'M6 6 L18 18 M6 18 L18 6', filled: false },
  dot: { d: 'M12 12 m-6 0 a6 6 0 1 0 12 0 a6 6 0 1 0 -12 0', filled: true },
  star: {
    d: 'M12 2 L14.9 8.9 L22.4 9.5 L16.7 14.4 L18.5 21.7 L12 17.8 L5.5 21.7 L7.3 14.4 L1.6 9.5 L9.1 8.9 Z',
    filled: true,
  },
};

/**
 * A small icon â€” check, cross, dot, or star â€” that pops into place on
 * `SPRING_SMOOTH` via {@link entryScale} (scale 0 â†’ 1 plus opacity fade).
 * Universal state primitive; the accent is earned (the icon itself is the
 * single accent moment). No overshoot, no flourish.
 *
 * @example
 * <IconPop icon="check" />
 */
export const IconPop: React.FC<IconPopProps> = ({
  icon, delay, duration, size, color, strokeWidth,
}) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const { opacity, transform } = entryScale({
    frame,
    fps,
    delay,
    durationInFrames: duration,
    from: 0,
  });

  const { d, filled } = ICONS[icon];

  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 24 24"
      style={{ opacity, transform }}
      fill={filled ? color : 'none'}
      stroke={filled ? 'none' : color}
      strokeWidth={strokeWidth}
      strokeLinecap="round"
      strokeLinejoin="round"
    >
      <path d={d} />
    </svg>
  );
};

// Re-exports the Zod schema so tooling (registry builds, docs site,
// training-data pipelines) can consume props validation without pulling
// in the component itself.
export { iconPopSchema, type IconPopProps } from './IconPop';

# IconPop

A small state icon â€” `check`, `cross`, `dot`, or `star` â€” that pops into place on `SPRING_SMOOTH` via `entryScale` (scale 0 â†’ 1 plus opacity fade). The universal state primitive: success, error, presence, emphasis. The icon itself is the single accent moment â€” color is earned, not sprinkled.

## Props

| Name | Type | Default | Notes |
| --- | --- | --- | --- |
| `icon` | `'check' \| 'cross' \| 'dot' \| 'star'` | `'check'` | Which glyph to render. `check`/`cross` are stroked; `dot`/`star` are filled. |
| `delay` | `integer â‰¥ 0` | `0` | Frames before the animation starts. |
| `duration` | `integer â‰¥ 1` | `DURATION.base` (18) | Target frames to settle. With `SPRING_SMOOTH` the visible motion settles in roughly this range. |
| `size` | `number` | `96` | Width and height in pixels (square). |
| `color` | `string` | `"#D96B82"` | Icon color â€” defaults to `--onda-accent`. |
| `strokeWidth` | `number` | `3` | Stroke width for outline icons. Ignored by `dot` and `star`. |

## Usage

```tsx
import { Composition } from 'remotion';
import { IconPop, iconPopSchema } from './components/onda/icon-pop/IconPop';

export const Root: React.FC = () => (
  <Composition
    id="MyIconPop"
    component={IconPop}
    durationInFrames={45}
    fps={30}
    width={1080}
    height={1920}
    schema={iconPopSchema}
    defaultProps={{
      icon: 'check',
      delay: 0,
      duration: 18,
      size: 96,
      color: '#D96B82',
      strokeWidth: 3,
    }}
  />
);
```

## Motion notes

- Powered by `entryScale({ ..., from: 0 })` from `lib/choreography.ts` â€” scale 0 â†’ 1 plus opacity, driven by `SPRING_SMOOTH`. **No overshoot.** Despite the "pop" name, the icon settles confidently to 1.0 without bouncing past.
- Duration defaults to `DURATION.base` (18 frames â‰ˆ 0.6s at 30fps).
- The whole motion is one move: scale and opacity, nothing else. No rotation, no flourish, no particle burst â€” restraint is the point.
- All `interpolate` calls (inside `entryScale`) clamp at both ends â€” correct on frame 0 and on any frame past `delay + duration`.
- The default color is `--onda-accent` because the icon *is* the accent moment in its scene. Use neutrals only if you've already spent the accent elsewhere.
